"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { useEffect, useState } from "react";

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 40);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const navItem = (label: string, href: string) => (
    <motion.div whileHover={{ y: -2 }}>
      <Link
        href={href}
        className="relative text-[13px] tracking-[2px] font-medium uppercase group"
      >
        {label}
        <span className="absolute left-0 -bottom-1 h-[1.5px] w-0 bg-[#fbc02d] transition-all duration-300 group-hover:w-full"></span>
      </Link>
    </motion.div>
  );

  return (
    <header
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${
        scrolled
          ? "bg-white/90 backdrop-blur-md text-black"
          : "bg-transparent text-white"
      }`}
    >
      <div className="max-w-7xl mx-auto px-6 py-5 flex items-center justify-between relative">

        {/* LEFT */}
        <div className="hidden md:flex gap-8">
          {navItem("About Us", "#")}
          {navItem("What We Do", "#")}
          {navItem("Join Us", "#")}
        </div>

        {/* CENTER LOGO */}
        <div className="absolute left-1/2 -translate-x-1/2 flex items-center gap-2">
          <div className="text-xl">🌿</div>
          <h1 className="text-lg font-semibold tracking-wide">
            Akriti Sky Morph
          </h1>
        </div>

        {/* RIGHT */}
        <div className="hidden md:flex gap-8">
          {navItem("Locations", "#")}
          {navItem("Contact Us", "#")}
        </div>

        {/* MOBILE */}
        <div className="md:hidden text-xl">☰</div>

      </div>
    </header>
  );
};

export default Navbar;